import React, { useState, useEffect } from 'react';
import { Link, useSearchParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { FiPackage, FiSearch, FiFilter, FiCheck, FiPhone, FiLock } from 'react-icons/fi';

function Products() {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const [products, setProducts] = useState([]);
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedProduct, setSelectedProduct] = useState(null);
  const [viewMode, setViewMode] = useState('list'); // 'list' or 'grid'
  const [phoneNumbers, setPhoneNumbers] = useState({}); // Store phone numbers by product ID
  const [hasSubscription, setHasSubscription] = useState(false);
  const [checkingPhones, setCheckingPhones] = useState({}); // Track which products are loading phone
  const [showSubscriptionModal, setShowSubscriptionModal] = useState(false);
  const [filters, setFilters] = useState({
    search: searchParams.get('search') || '',
    category: searchParams.get('category') || '',
    minPrice: '',
    maxPrice: ''
  });

  useEffect(() => {
    fetchCategories();
    fetchProducts();
    checkUserSubscription();
  }, [filters]);

  const checkUserSubscription = async () => {
    const token = localStorage.getItem('token');
    const user = localStorage.getItem('user');
    if (token && user) {
      try {
        const userData = JSON.parse(user);
        const response = await axios.get(`/api/subscriptions/check/${userData.id}`);
        setHasSubscription(response.data.has_subscription);
      } catch (error) {
        console.error('Error checking subscription:', error);
      }
    }
  };

  const fetchCategories = async () => {
    try {
      const response = await axios.get('/api/categories');
      setCategories(response.data);
    } catch (error) {
      console.error('Error fetching categories:', error);
    }
  };

  const fetchProducts = async () => {
    setLoading(true);
    try {
      const params = new URLSearchParams();
      if (filters.search) params.append('search', filters.search);
      if (filters.category) params.append('category', filters.category);
      if (filters.minPrice) params.append('min_price', filters.minPrice);
      if (filters.maxPrice) params.append('max_price', filters.maxPrice);

      const response = await axios.get(`/api/products?${params.toString()}`);
      setProducts(response.data);
      // Auto-select first product if none selected
      if (response.data.length > 0 && !selectedProduct) {
        setSelectedProduct(response.data[0].id);
      }
    } catch (error) {
      console.error('Error fetching products:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleFilterChange = (key, value) => {
    setFilters(prev => ({ ...prev, [key]: value }));
  };

  const handleProductSelect = (productId) => {
    setSelectedProduct(productId);
    navigate(`/products/${productId}`, { replace: true });
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-dark-bg via-dark-surface to-dark-bg py-8">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="mb-8 flex items-center justify-between">
          <div>
            <h1 className="text-4xl font-bold mb-2 text-dark-text">Products</h1>
            <p className="text-dark-muted">Find the products you need from verified suppliers</p>
          </div>
          <div className="flex gap-2">
            <button
              onClick={() => setViewMode('list')}
              className={`px-4 py-2 rounded-lg ${viewMode === 'list' ? 'bg-accent-purple text-white' : 'glass-effect border border-dark-border text-dark-text'}`}
            >
              List
            </button>
            <button
              onClick={() => setViewMode('grid')}
              className={`px-4 py-2 rounded-lg ${viewMode === 'grid' ? 'bg-accent-purple text-white' : 'glass-effect border border-dark-border text-dark-text'}`}
            >
              Grid
            </button>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
          {/* Filters Sidebar */}
          <aside className="lg:col-span-1">
            <div className="glass-effect rounded-xl p-6 sticky top-24">
              <div className="flex items-center gap-2 mb-6">
                <FiFilter className="text-accent-purple" />
                <h3 className="text-xl font-bold text-dark-text">Filters</h3>
              </div>
              
              <div className="space-y-5">
                <div>
                  <label className="block mb-2 font-semibold text-dark-text text-sm">Search</label>
                  <div className="relative">
                    <FiSearch className="absolute left-3 top-1/2 transform -translate-y-1/2 text-dark-muted" />
                    <input
                      type="text"
                      placeholder="Search products..."
                      value={filters.search}
                      onChange={(e) => handleFilterChange('search', e.target.value)}
                      className="w-full pl-10 pr-4 py-2 rounded-lg bg-dark-card border border-dark-border text-dark-text placeholder-dark-muted focus:border-accent-purple focus:outline-none"
                    />
                  </div>
                </div>

                <div>
                  <label className="block mb-2 font-semibold text-dark-text text-sm">Category</label>
                  <select
                    value={filters.category}
                    onChange={(e) => handleFilterChange('category', e.target.value)}
                    className="w-full px-4 py-2 rounded-lg bg-dark-card border border-dark-border text-dark-text focus:border-accent-purple focus:outline-none"
                  >
                    <option value="">All Categories</option>
                    {categories.map(cat => (
                      <option key={cat.id} value={cat.id}>{cat.name}</option>
                    ))}
                  </select>
                </div>

                <div>
                  <label className="block mb-2 font-semibold text-dark-text text-sm">Price Range</label>
                  <input
                    type="number"
                    placeholder="Min Price"
                    value={filters.minPrice}
                    onChange={(e) => handleFilterChange('minPrice', e.target.value)}
                    className="w-full px-4 py-2 rounded-lg bg-dark-card border border-dark-border text-dark-text placeholder-dark-muted focus:border-accent-purple focus:outline-none mb-2"
                  />
                  <input
                    type="number"
                    placeholder="Max Price"
                    value={filters.maxPrice}
                    onChange={(e) => handleFilterChange('maxPrice', e.target.value)}
                    className="w-full px-4 py-2 rounded-lg bg-dark-card border border-dark-border text-dark-text placeholder-dark-muted focus:border-accent-purple focus:outline-none"
                  />
                </div>
              </div>
            </div>
          </aside>

          {/* Products List/Grid */}
          <main className="lg:col-span-3">
            {loading ? (
              <div className="text-center py-20 text-dark-muted">
                <div className="animate-pulse">Loading products...</div>
              </div>
            ) : products.length === 0 ? (
              <div className="glass-effect rounded-xl p-12 text-center">
                <FiPackage className="mx-auto text-6xl text-dark-muted mb-4" />
                <p className="text-dark-muted text-lg">No products found. Try adjusting your filters.</p>
              </div>
            ) : (
              <>
                <div className="mb-4 text-dark-muted">
                  Showing {products.length} product{products.length !== 1 ? 's' : ''}
                </div>
                
                {viewMode === 'list' ? (
                  <div className="space-y-3">
                    {products.map(product => (
                      <div
                        key={product.id}
                        onClick={() => handleProductSelect(product.id)}
                        className={`glass-effect rounded-xl p-4 cursor-pointer transition-all ${
                          selectedProduct === product.id 
                            ? 'border-2 border-accent-purple bg-accent-purple/10' 
                            : 'hover:glow-effect border border-dark-border'
                        }`}
                      >
                        <div className="flex items-center gap-4">
                          <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center flex-shrink-0 ${
                            selectedProduct === product.id 
                              ? 'border-accent-purple bg-accent-purple' 
                              : 'border-dark-border'
                          }`}>
                            {selectedProduct === product.id && <FiCheck className="text-white text-xs" />}
                          </div>
                          <div className="w-24 h-24 bg-dark-card rounded-lg overflow-hidden flex-shrink-0">
                            {product.image_url ? (
                              <img src={product.image_url} alt={product.name} className="w-full h-full object-cover" />
                            ) : (
                              <div className="w-full h-full flex items-center justify-center text-dark-muted">
                                <FiPackage className="text-2xl" />
                              </div>
                            )}
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="flex items-start justify-between gap-4">
                              <div className="flex-1">
                                <h3 className="text-lg font-semibold text-dark-text mb-1">{product.name}</h3>
                                <p className="text-sm text-dark-muted line-clamp-2 mb-2">{product.description}</p>
                                <div className="flex items-center gap-4 text-sm">
                                  <span className="text-accent-orange font-bold">
                                    ₹{product.price?.toLocaleString() || 'Price on Request'}
                                  </span>
                                  <span className="text-dark-muted">{product.company_name}</span>
                                  <span className="text-dark-muted">{product.location}</span>
                                </div>
                              </div>
                              {product.featured && (
                                <span className="px-2 py-1 bg-gradient-to-r from-accent-purple to-accent-pink text-white text-xs font-semibold rounded flex-shrink-0">
                                  Featured
                                </span>
                              )}
                            </div>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                ) : (
                  <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
                    {products.map(product => (
                      <Link
                        key={product.id}
                        to={`/products/${product.id}`}
                        className="glass-effect rounded-xl overflow-hidden hover:glow-effect transition-all group"
                      >
                        <div className="relative h-48 bg-dark-card overflow-hidden">
                          {product.image_url ? (
                            <img 
                              src={product.image_url} 
                              alt={product.name}
                              className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-300"
                            />
                          ) : (
                            <div className="w-full h-full flex items-center justify-center text-dark-muted">
                              <FiPackage className="text-4xl" />
                            </div>
                          )}
                          {product.featured && (
                            <div className="absolute top-2 right-2 px-2 py-1 bg-gradient-to-r from-accent-purple to-accent-pink text-white text-xs font-semibold rounded">
                              Featured
                            </div>
                          )}
                        </div>
                        <div className="p-5">
                          <h3 className="text-lg font-semibold mb-2 text-dark-text line-clamp-2 group-hover:text-accent-purple transition-colors">
                            {product.name}
                          </h3>
                          <p className="text-sm text-dark-muted mb-3 line-clamp-2">
                            {product.description}
                          </p>
                          <div className="flex items-center justify-between">
                            <div>
                              <p className="text-xl font-bold text-accent-orange">
                                ₹{product.price?.toLocaleString() || 'Price on Request'}
                              </p>
                              <p className="text-xs text-dark-muted mt-1">{product.company_name}</p>
                            </div>
                          </div>
                          <p className="text-xs text-dark-muted mt-2">{product.location}</p>
                        </div>
                      </Link>
                    ))}
                  </div>
                )}
              </>
            )}
          </main>
        </div>
      </div>
    </div>
  );
}

export default Products;
